#!/usr/bin/env python
"""
Backup script that creates compressed archives of user directories.
Supports multiple compression formats: tar.gz, tar.bz2, zip, 7z
Compatible with Python 2.6+ and Python 3.x
"""

from __future__ import print_function

import os
import sys
import re
import tarfile
import zipfile
import subprocess
import datetime
import shutil
import errno


SUPPORTED_FORMATS = ['tar.gz', 'tar.bz2', 'zip', '7z']


def validate_path(path):
    """Validate and sanitize the directory path to prevent path traversal and injection."""
    if not path:
        raise ValueError("Path cannot be empty.")

    # Resolve to absolute path and normalize
    abs_path = os.path.realpath(os.path.abspath(path))

    # Check for null bytes (injection vector in older Python versions)
    if '\x00' in abs_path:
        raise ValueError("Path contains null bytes - possible injection attempt.")

    # Check that the path exists and is a directory
    if not os.path.exists(abs_path):
        raise ValueError("Path does not exist: %s" % abs_path)

    if not os.path.isdir(abs_path):
        raise ValueError("Path is not a directory: %s" % abs_path)

    # Check that we have read access
    if not os.access(abs_path, os.R_OK):
        raise ValueError("No read access to directory: %s" % abs_path)

    return abs_path


def validate_format(fmt):
    """Validate the compression format."""
    fmt = fmt.lower().strip()
    if fmt not in SUPPORTED_FORMATS:
        raise ValueError(
            "Unsupported format: '%s'. Supported formats: %s"
            % (fmt, ', '.join(SUPPORTED_FORMATS))
        )
    return fmt


def sanitize_filename(name):
    """Sanitize a string for use in a filename - prevent injection in filenames."""
    # Only allow alphanumeric, hyphens, underscores, and dots
    sanitized = re.sub(r'[^a-zA-Z0-9._\-]', '_', name)
    # Remove leading dots to prevent hidden files
    sanitized = sanitized.lstrip('.')
    if not sanitized:
        sanitized = 'backup'
    return sanitized


def generate_backup_name(source_dir, fmt):
    """Generate a backup filename based on source directory and timestamp."""
    dir_name = os.path.basename(source_dir)
    if not dir_name:
        dir_name = 'root'

    dir_name = sanitize_filename(dir_name)
    timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')

    if fmt == 'tar.gz':
        ext = '.tar.gz'
    elif fmt == 'tar.bz2':
        ext = '.tar.bz2'
    elif fmt == 'zip':
        ext = '.zip'
    elif fmt == '7z':
        ext = '.7z'
    else:
        ext = '.tar.gz'

    return "backup_%s_%s%s" % (dir_name, timestamp, ext)


def get_backup_dir():
    """Get or create the backup output directory."""
    # Use a dedicated backup directory in the user's home
    home = os.path.expanduser('~')
    backup_dir = os.path.join(home, 'backups')

    try:
        os.makedirs(backup_dir)
    except OSError as e:
        if e.errno != errno.EEXIST:
            raise

    return backup_dir


def create_tar_gz(source_dir, output_path):
    """Create a tar.gz archive."""
    print("Creating tar.gz archive...")
    with tarfile.open(output_path, 'w:gz') as tar:
        # Use the basename of the source as the archive root
        arcname = os.path.basename(source_dir)
        tar.add(source_dir, arcname=arcname)
    print("Archive created: %s" % output_path)
    return True


def create_tar_bz2(source_dir, output_path):
    """Create a tar.bz2 archive."""
    print("Creating tar.bz2 archive...")
    with tarfile.open(output_path, 'w:bz2') as tar:
        arcname = os.path.basename(source_dir)
        tar.add(source_dir, arcname=arcname)
    print("Archive created: %s" % output_path)
    return True


def create_zip(source_dir, output_path):
    """Create a zip archive."""
    print("Creating zip archive...")
    base_name = os.path.basename(source_dir)

    with zipfile.ZipFile(output_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for root, dirs, files in os.walk(source_dir):
            for filename in files:
                file_path = os.path.join(root, filename)
                # Calculate the archive name relative to the parent of source_dir
                rel_path = os.path.relpath(file_path, os.path.dirname(source_dir))
                try:
                    zipf.write(file_path, rel_path)
                except (OSError, IOError) as e:
                    print("Warning: Could not add file '%s': %s" % (file_path, e))

        # Also add empty directories
        for root, dirs, files in os.walk(source_dir):
            for dirname in dirs:
                dir_path = os.path.join(root, dirname)
                rel_path = os.path.relpath(dir_path, os.path.dirname(source_dir))
                # Add directory entry
                zipf.write(dir_path, rel_path)

    print("Archive created: %s" % output_path)
    return True


def find_7z_binary():
    """Find the 7z binary on the system."""
    possible_names = ['7z', '7za', '7zr']
    possible_paths = [
        '/usr/bin', '/usr/local/bin', '/bin',
        '/usr/lib/p7zip', '/opt/local/bin'
    ]

    for name in possible_names:
        for path_dir in possible_paths:
            full_path = os.path.join(path_dir, name)
            if os.path.isfile(full_path) and os.access(full_path, os.X_OK):
                return full_path

    # Try using 'which' command as fallback (safely)
    for name in possible_names:
        try:
            proc = subprocess.Popen(
                ['which', name],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE
            )
            stdout, _ = proc.communicate()
            if proc.returncode == 0:
                result = stdout.strip()
                if isinstance(result, bytes):
                    result = result.decode('utf-8', errors='replace')
                if result and os.path.isfile(result):
                    return result
        except (OSError, IOError):
            continue

    return None


def create_7z(source_dir, output_path):
    """Create a 7z archive using the 7z command-line tool."""
    print("Creating 7z archive...")

    binary = find_7z_binary()
    if binary is None:
        print("Error: 7z/7za/7zr not found on this system.")
        print("Install p7zip: apt-get install p7zip-full (Debian/Ubuntu)")
        print("            or: yum install p7zip p7zip-plugins (RHEL/CentOS)")
        return False

    # Build command as a list to prevent shell injection
    # Never use shell=True with user-provided input
    cmd = [
        binary,
        'a',           # add to archive
        '-t7z',        # 7z format
        '-mx=5',       # compression level 5 (normal)
        '-mmt=on',     # multi-threading
        output_path,   # output file
        source_dir     # source directory
    ]

    try:
        proc = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )
        stdout, stderr = proc.communicate()

        if proc.returncode != 0:
            stderr_str = stderr
            if isinstance(stderr_str, bytes):
                stderr_str = stderr_str.decode('utf-8', errors='replace')
            print("Error creating 7z archive (exit code %d): %s" % (proc.returncode, stderr_str))
            return False

        print("Archive created: %s" % output_path)
        return True

    except OSError as e:
        print("Error running 7z: %s" % e)
        return False


def get_file_size_human(filepath):
    """Get human-readable file size."""
    size = os.path.getsize(filepath)
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size < 1024.0:
            return "%.1f %s" % (size, unit)
        size /= 1024.0
    return "%.1f PB" % size


def get_dir_size(path):
    """Calculate total directory size."""
    total = 0
    for root, dirs, files in os.walk(path):
        for f in files:
            fp = os.path.join(root, f)
            try:
                total += os.path.getsize(fp)
            except (OSError, IOError):
                pass
    return total


def get_dir_size_human(path):
    """Get human-readable directory size."""
    size = get_dir_size(path)
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size < 1024.0:
            return "%.1f %s" % (size, unit)
        size /= 1024.0
    return "%.1f PB" % size


def create_backup(source_dir, fmt, output_dir=None):
    """Main backup function."""
    # Validate inputs
    source_dir = validate_path(source_dir)
    fmt = validate_format(fmt)

    if output_dir is None:
        output_dir = get_backup_dir()
    else:
        output_dir = validate_path(output_dir)

    # Generate output filename
    backup_name = generate_backup_name(source_dir, fmt)
    output_path = os.path.join(output_dir, backup_name)

    # Check if output file already exists
    if os.path.exists(output_path):
        print("Warning: Output file already exists: %s" % output_path)
        return False

    print("=" * 60)
    print("Backup Configuration:")
    print("  Source:      %s" % source_dir)
    print("  Source size: %s" % get_dir_size_human(source_dir))
    print("  Format:      %s" % fmt)
    print("  Output:      %s" % output_path)
    print("=" * 60)

    # Create the backup based on format
    creators = {
        'tar.gz': create_tar_gz,
        'tar.bz2': create_tar_bz2,
        'zip': create_zip,
        '7z': create_7z,
    }

    creator = creators.get(fmt)
    if creator is None:
        print("Error: No creator for format '%s'" % fmt)
        return False

    start_time = datetime.datetime.now()

    try:
        success = creator(source_dir, output_path)
    except (OSError, IOError) as e:
        print("Error creating backup: %s" % e)
        # Clean up partial file
        if os.path.exists(output_path):
            try:
                os.remove(output_path)
            except OSError:
                pass
        return False
    except Exception as e:
        print("Unexpected error creating backup: %s" % e)
        if os.path.exists(output_path):
            try:
                os.remove(output_path)
            except OSError:
                pass
        return False

    end_time = datetime.datetime.now()
    elapsed = end_time - start_time

    if success and os.path.exists(output_path):
        print("")
        print("Backup completed successfully!")
        print("  Archive size: %s" % get_file_size_human(output_path))
        print("  Time elapsed: %s" % str(elapsed))
        print("  Output file:  %s" % output_path)
        return True
    else:
        print("Backup failed.")
        return False


def print_usage():
    """Print usage information."""
    script_name = os.path.basename(sys.argv[0])
    print("Usage: %s <directory_path> <format> [output_directory]" % script_name)
    print("")
    print("Arguments:")
